const pptxgen = require('pptxgenjs');
const pres = new pptxgen();
pres.layout = 'LAYOUT_16x9';

// === SLIDE 1: Dark Title Slide ===
const s1 = pres.addSlide();
s1.background = { color: '1E2761' };
s1.addText('Q3 2024', { x: 0.8, y: 1.5, w: 8, h: 0.6, fontSize: 16, color: 'CADCFC', fontFace: 'Calibri Light', charSpacing: 6 });
