s2.background = { color: 'F8F9FC' };
s2.addText('Key Performance Indicators', { x: 0.5, y: 0.3, w: 9, h: 0.6, fontSize: 24, color: '1E2761', fontFace: 'Calibri', bold: true });
const kpis = [
  { label: 'Total Revenue', value: '$4.2M', change: '+18% YoY', x: 0.4 },
  { label: 'Growth Rate', value: '18%', change: '+3pts vs Q2', x: 2.9 },
  { label: 'NPS Score', value: '72', change: '+5 vs Q2', x: 5.4 },
  { label: 'CAC', value: '$142', change: '-12% YoY', x: 7.9 }
];
kpis.forEach(k => {
  s2.addShape(pres.shapes.RECTANGLE, { x: k.x, y: 1.2, w: 2.2, h: 2.8, fill: { color: 'FFFFFF' }, shadow: { type: 'outer', color: '000000', blur: 8, offset: 2, angle: 135, opacity: 0.1 }, line: { color: 'EEEEEE', width: 0.5 } });
  s2.addShape(pres.shapes.RECTANGLE, { x: k.x, y: 1.2, w: 2.2, h: 0.08, fill: { color: '1E2761' }, line: { color: '1E2761' } });
  s2.addText(k.label, { x: k.x + 0.15, y: 1.4, w: 1.9, h: 0.4, fontSize: 11, color: '6B7280', fontFace: 'Calibri Light' });
  s2.addText(k.value, { x: k.x + 0.1, y: 1.9, w: 2.0, h: 0.8, fontSize: 36, color: '1E2761', fontFace: 'Calibri', bold: true });
  s2.addText(k.change, { x: k.x + 0.15, y: 2.75, w: 1.9, h: 0.4, fontSize: 11, color: '059669', fontFace: 'Calibri Light' });
});

// === SLIDE 3: Revenue Chart ===
