s3.background = { color: 'FFFFFF' };
s3.addText('Monthly Revenue · Jan – Sep 2024', { x: 0.5, y: 0.3, w: 9, h: 0.6, fontSize: 24, color: '1E2761', fontFace: 'Calibri', bold: true });
s3.addChart(pres.charts.BAR, [{ name: 'Revenue ($K)', labels: ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep'], values: [320,345,390,410,440,460,490,510,560] }], { x: 0.5, y: 1.0, w: 9, h: 4.0, barDir: 'col', chartColors: ['1E2761'], chartArea: { fill: { color: 'FFFFFF' }, roundedCorners: true }, catAxisLabelColor: '6B7280', valAxisLabelColor: '6B7280', valGridLine: { color: 'E5E7EB', size: 0.5 }, catGridLine: { style: 'none' }, showValue: true, dataLabelColor: '1E2761', showLegend: false });

// === SLIDE 4: Two Column — Wins vs Challenges ===
