s4.background = { color: 'F8F9FC' };
s4.addText('Q3 Highlights & Challenges', { x: 0.5, y: 0.3, w: 9, h: 0.6, fontSize: 24, color: '1E2761', fontFace: 'Calibri', bold: true });
