wins.forEach((w, i) => { s4.addText(w, { x: 0.65, y: 1.9 + i * 0.55, w: 3.7, h: 0.45, fontSize: 13, color: '374151', fontFace: 'Calibri Light' }); });
// Right column - Challenges
