actions.forEach((a, i) => {
  s5.addShape(pres.shapes.OVAL, { x: 0.8, y: 1.5 + i * 0.7, w: 0.38, h: 0.38, fill: { color: 'CADCFC' }, line: { color: 'CADCFC' } });
  s5.addText(String(i + 1), { x: 0.8, y: 1.5 + i * 0.7, w: 0.38, h: 0.38, fontSize: 13, color: '1E2761', fontFace: 'Calibri', bold: true, align: 'center', valign: 'middle' });
  s5.addText(a, { x: 1.35, y: 1.5 + i * 0.7, w: 7.8, h: 0.38, fontSize: 14, color: 'CADCFC', fontFace: 'Calibri Light', valign: 'middle' });
});

