stats.forEach((s, i) => {
  const x = 0.4 + i * 3.2;
  s2.addShape(pres.shapes.RECTANGLE, { x, y: 1.2, w: 2.8, h: 3.5, fill: { color: i === 1 ? 'F96167' : 'F8F9FC' }, line: { color: 'EEEEEE' } });
  s2.addText(s.val, { x: x + 0.15, y: 1.7, w: 2.5, h: 1.2, fontSize: 44, color: i === 1 ? 'FFFFFF' : 'F96167', fontFace: 'Georgia', bold: true, align: 'center' });
  s2.addText(s.label, { x: x + 0.15, y: 3.0, w: 2.5, h: 1.2, fontSize: 13, color: i === 1 ? 'FFFFFF' : '374151', fontFace: 'Calibri Light', align: 'center' });
});

// === SLIDE 3: Solution — Three Pillars ===
const s3 = pres.addSlide();
s3.background = { color: 'F8F9FC' };
