  { title: 'Auto-Log', desc: 'AI captures every call, email, and meeting. Zero manual input.', color: 'F96167' },
  { title: 'Smart Coach', desc: 'Real-time nudges guide reps through every deal stage.', color: '2F3C7E' },
  { title: 'Pipeline Intel', desc: 'Forecast with 94% accuracy using deal-signal AI.', color: 'F9E795' }
];
pillars.forEach((p, i) => {
  const x = 0.4 + i * 3.15;
  s3.addShape(pres.shapes.RECTANGLE, { x, y: 1.2, w: 2.85, h: 3.8, fill: { color: 'FFFFFF' }, shadow: { type: 'outer', color: '000000', blur: 8, offset: 2, angle: 135, opacity: 0.1 } });
  s3.addShape(pres.shapes.RECTANGLE, { x, y: 1.2, w: 2.85, h: 0.5, fill: { color: p.color }, line: { color: p.color } });
  s3.addText(p.title, { x: x + 0.15, y: 1.9, w: 2.55, h: 0.6, fontSize: 18, color: '1F2937', fontFace: 'Georgia', bold: true });
  s3.addText(p.desc, { x: x + 0.15, y: 2.65, w: 2.55, h: 1.8, fontSize: 13, color: '4B5563', fontFace: 'Calibri Light' });
});

// === SLIDE 4: Traction ===
