  s4.addText(m.val, { x: 0.4 + i * 2.35, y: 1.1, w: 2.1, h: 0.8, fontSize: 32, color: 'F9E795', fontFace: 'Georgia', bold: true, align: 'center' });
  s4.addText(m.label, { x: 0.4 + i * 2.35, y: 1.9, w: 2.1, h: 0.45, fontSize: 11, color: 'CADCFC', fontFace: 'Calibri Light', align: 'center' });
});
s4.addChart(pres.charts.LINE, [{ name: 'ARR ($K)', labels: ['Jan','Feb','Mar','Apr','May','Jun','Jul','Aug','Sep'], values: [280,320,370,430,510,620,760,920,1100] }], { x: 0.5, y: 2.8, w: 9, h: 2.6, chartColors: ['F96167'], lineSize: 3, lineSmooth: true, chartArea: { fill: { color: 'FFFFFF' } }, catAxisLabelColor: '9CA3AF', valAxisLabelColor: '9CA3AF', valGridLine: { color: 'F3F4F6', size: 0.5 }, catGridLine: { style: 'none' }, showLegend: false });

// === SLIDE 5: Team ===
